import SwiftUI

/// 사주 4기둥 중 한 기둥을 표시하는 셀 뷰.
///
/// - Parameters:
///   - pillar: 기둥 데이터(천간·지지).
///   - columnLabel: 기둥 이름 한자 (時/日/月/年).
///   - isDayMaster: 일간 여부 — true이면 천간 박스 배경을 강조 토큰으로 채색.
struct SajuPillarCellView: View {
    let pillar: Pillar
    let columnLabel: String
    let isDayMaster: Bool

    var body: some View {
        VStack(spacing: 4) {
            Text(columnLabel)
                .font(.system(size: 10))
                .foregroundStyle(DesignTokens.muted)

            // 천간(天干) 박스
            Text(pillar.heavenlyStem)
                .font(.system(size: 14, weight: .bold))
                .foregroundStyle(DesignTokens.ink)
                .frame(maxWidth: .infinity)
                .frame(height: 36)
                .background(isDayMaster ? DesignTokens.dayMasterHighlight : DesignTokens.bg)
                .cornerRadius(4)
                .overlay(
                    RoundedRectangle(cornerRadius: 4)
                        .stroke(DesignTokens.line3, lineWidth: 0.5)
                )

            // 지지(地支) 박스
            Text(pillar.earthlyBranch)
                .font(.system(size: 14, weight: .bold))
                .foregroundStyle(DesignTokens.ink)
                .frame(maxWidth: .infinity)
                .frame(height: 36)
                .background(DesignTokens.gray)
                .cornerRadius(4)
                .overlay(
                    RoundedRectangle(cornerRadius: 4)
                        .stroke(DesignTokens.line3, lineWidth: 0.5)
                )
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel("\(columnLabel), 천간 \(pillar.heavenlyStem), 지지 \(pillar.earthlyBranch)")
        .accessibilityAddTraits(isDayMaster ? [.isHeader] : [])
        .accessibilityIdentifier("SajuPillarCell_\(pillar.position.rawValue)")
    }
}

import SwiftUI

/// Block A — 내 원국 4주 카드.
///
/// 상단 헤더("내 사주 원국" / "전체 보기 ›"), 4-column 기둥 grid,
/// 일간 한줄 박스 순서로 배치된다.
struct SajuOriginCardView: View {
    let provider: any UserSajuOriginProviding
    let onViewAll: () -> Void

    /// 항상 [時, 日, 月, 年] 고정 순서.
    private let displayOrder: [Pillar.Position] = [.hour, .day, .month, .year]

    var body: some View {
        // Precondition: provider must supply exactly 4 pillars.
        let pillars = provider.pillars
        precondition(pillars.count == 4,
            "UserSajuOriginProviding must supply exactly 4 pillars (hour/day/month/year)")

        let pillarMap: [Pillar.Position: Pillar] = Dictionary(
            uniqueKeysWithValues: pillars.map { ($0.position, $0) }
        )

        return VStack(spacing: 8) {
            // 헤더 행
            HStack {
                Text("내 사주 원국")
                    .font(.system(size: 12))
                    .foregroundStyle(DesignTokens.muted)
                    .accessibilityIdentifier("SajuOriginCardHeaderLabel")
                Spacer()
                Button(action: onViewAll) {
                    Text("전체 보기 ›")
                        .font(.system(size: 12))
                        .foregroundStyle(DesignTokens.muted)
                }
                .accessibilityHint("준비중")
                .accessibilityIdentifier("SajuOriginCardViewAllButton")
            }

            // 4-column grid
            HStack(spacing: 8) {
                ForEach(displayOrder, id: \.self) { position in
                    SajuPillarCellView(
                        pillar: pillarMap[position]!,
                        columnLabel: label(for: position),
                        isDayMaster: position == .day
                    )
                    .frame(maxWidth: .infinity)
                }
            }

            // 일간 한줄 박스
            Text(provider.dayMasterLine)
                .font(.system(size: 13))
                .foregroundStyle(DesignTokens.ink)
                .frame(maxWidth: .infinity, alignment: .leading)
                .padding(10)
                .background(DesignTokens.dayMasterLineBg)
                .cornerRadius(6)
                .fixedSize(horizontal: false, vertical: true)
                .accessibilityIdentifier("SajuDayMasterLine")
        }
        .padding(16)
        .background(DesignTokens.bg)
        .accessibilityElement(children: .contain)
        .accessibilityIdentifier("SajuOriginCard")
    }

    private func label(for position: Pillar.Position) -> String {
        switch position {
        case .hour:  return "時"
        case .day:   return "日"
        case .month: return "月"
        case .year:  return "年"
        }
    }
}

import SwiftUI

/// 카테고리 카드 1개.
///
/// `summary`가 nil이면 "데이터 없음" placeholder를 표시한다.
/// 카드 전체(좌측 텍스트 + 우측 chevron/"근거 보기" 포함)가 단일 `Button`으로
/// 감싸여 있으므로 "근거 보기" 영역도 카드 전체 탭과 동일한 동작을 한다.
struct SajuCategoryCardView: View {
    let summary: SajuCategorySummary?
    let kind: SajuCategorySummary.Kind
    let onTap: () -> Void

    var body: some View {
        if let summary {
            Button(action: onTap) {
                HStack(alignment: .center, spacing: 10) {
                    // 좌측 텍스트 영역
                    VStack(alignment: .leading, spacing: 4) {
                        Text(summary.title)
                            .font(.system(size: 14, weight: .semibold))
                            .foregroundStyle(DesignTokens.ink)

                        Text(summary.summary)
                            .font(.system(size: 13))
                            .foregroundStyle(DesignTokens.muted)
                            .fixedSize(horizontal: false, vertical: true)
                            .multilineTextAlignment(.leading)

                        if let badge = summary.badge {
                            Text(badge)
                                .font(.system(size: 11, weight: .medium))
                                .foregroundStyle(DesignTokens.ink)
                                .padding(.horizontal, 8)
                                .padding(.vertical, 2)
                                .background(DesignTokens.gray2)
                                .cornerRadius(10)
                                .accessibilityIdentifier("SajuCategoryBadge_\(kind.rawValue)")
                        }
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)

                    // 우측 chevron / 근거 보기
                    VStack(alignment: .trailing, spacing: 4) {
                        Image(systemName: "chevron.right")
                            .font(.system(size: 14))
                            .foregroundStyle(DesignTokens.muted)

                        Text("근거 보기")
                            .font(.system(size: 11))
                            .foregroundStyle(DesignTokens.muted)
                            .underline()
                            .accessibilityIdentifier("SajuCategoryEvidence_\(kind.rawValue)")
                    }
                }
                .padding(.horizontal, 16)
                .padding(.vertical, 12)
                .frame(maxWidth: .infinity, minHeight: 44)
                .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .background(DesignTokens.bg)
            .accessibilityLabel(accessibilityLabel(for: summary))
            .accessibilityIdentifier("SajuCategoryCard_\(kind.rawValue)")
        } else {
            // Placeholder when no data
            HStack {
                Text("데이터 없음")
                    .font(.system(size: 13))
                    .foregroundStyle(DesignTokens.muted)
                Spacer()
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 12)
            .frame(maxWidth: .infinity, minHeight: 44)
            .background(DesignTokens.bg)
            .accessibilityIdentifier("SajuCategoryCard_\(kind.rawValue)")
        }
    }

    private func accessibilityLabel(for summary: SajuCategorySummary) -> String {
        var label = "\(summary.title), \(summary.summary)"
        if let badge = summary.badge {
            label += ", \(badge) 표시"
        }
        return label
    }
}

import SwiftUI

/// Block B — "내 사주 자세히" 섹션 헤더 + 5개 카테고리 카드 리스트.
///
/// 슬롯 순서는 항상 [오행 분포, 십성 분석, 대운·세운, 합충형파, 용신·희신]으로 고정.
/// provider에 해당 kind가 없으면 nil → "데이터 없음" placeholder 카드를 표시.
struct SajuCategoriesSection: View {
    let provider: any SajuCategoriesProviding
    let onNavigate: (SajuRoute) -> Void

    /// 항상 이 순서로 5슬롯 렌더.
    let displayOrder: [SajuCategorySummary.Kind] = [
        .elements, .tenGods, .daewoon, .hapchung, .yongsin
    ]

    var body: some View {
        VStack(alignment: .leading, spacing: 0) {
            Text("내 사주 자세히")
                .font(.system(size: 12, weight: .bold))
                .foregroundStyle(DesignTokens.ink)
                .padding(.horizontal, 16)
                .padding(.bottom, 8)
                .accessibilityIdentifier("SajuDetailSectionHeader")

            VStack(spacing: 8) {
                ForEach(displayOrder, id: \.self) { kind in
                    let summary = provider.categories.first(where: { $0.kind == kind })
                    SajuCategoryCardView(
                        summary: summary,
                        kind: kind,
                        onTap: { onNavigate(route(for: kind)) }
                    )
                }
            }
            .padding(.horizontal, 16)
        }
    }

    /// 카테고리 kind → SajuRoute 매핑.
    func route(for kind: SajuCategorySummary.Kind) -> SajuRoute {
        switch kind {
        case .elements: return .elements
        case .tenGods:  return .tenGods
        case .daewoon:  return .daewoonPlaceholder
        case .hapchung: return .hapchungPlaceholder
        case .yongsin:  return .yongsinPlaceholder
        }
    }
}

import SwiftUI

/// `SajuTabView`의 NavigationStack 내부 root 뷰.
///
/// Block A(원국 카드)와 Block B(5개 카테고리 카드 섹션)를 ScrollView 안에 배치하며,
/// WF4-01의 `SajuTabContentPlaceholderView`를 교체한다.
struct SajuTabContentView: View {
    let originProvider: any UserSajuOriginProviding
    let categoriesProvider: any SajuCategoriesProviding
    let onNavigate: (SajuRoute) -> Void

    var body: some View {
        ScrollView {
            VStack(spacing: 16) {
                SajuOriginCardView(
                    provider: originProvider,
                    onViewAll: { /* no-op — 전체 보기 화면은 WF4 범위 외 */ }
                )

                SajuCategoriesSection(
                    provider: categoriesProvider,
                    onNavigate: onNavigate
                )

                // WF4-03 섹션 공간 예약
                Spacer(minLength: 32)
            }
            .padding(.top, 16)
        }
        .accessibilityElement(children: .contain)
        .accessibilityIdentifier("SajuTabContent")
    }
}

